import{_ as l,o as e,c as a,a2 as r}from"./chunks/framework.BflysNKA.js";const c=JSON.parse('{"title":"关于 小蓝中转站","description":"","frontmatter":{},"headers":[],"relativePath":"about/index.md","filePath":"about/index.md","lastUpdated":1778577020000}'),t={name:"about/index.md"};function n(o,i,p,s,u,h){return e(),a("div",null,[...i[0]||(i[0]=[r('<h1 id="关于-xiaolan-ai" tabindex="-1">关于 小蓝中转站 <a class="header-anchor" href="#关于-xiaolan-ai" aria-label="Permalink to &quot;关于 小蓝中转站&quot;">​</a></h1><p>小蓝中转站 面向日常编码场景提供统一接入入口。</p><ul><li>官网：<a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">https://xiaolan1.cn</a></li><li>文档：<a href="https://docs.xiaolan1.cn" target="_blank" rel="noreferrer">https://docs.xiaolan1.cn</a></li><li>模型广场：<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></li><li>站长 QQ：<code>1527997732</code></li></ul><p>如果你是第一次接入，最省时间的路径通常是：</p><ol><li>先看 <a href="/guide/quick-start">快速接入</a></li><li>注册账号并充值</li><li>创建一把专用 Key</li><li>选一个最想用的工具先跑通</li></ol><p>先跑通一条最小链路，再去扩展第二个工具，通常会比一开始同时配置多个客户端更稳。</p><p>很多人第一次接入时，会把这三件事混在一起：</p><ul><li>工具怎么下载</li><li>Key 在哪里创建</li><li>地址、模型和 Key 该怎么填</li></ul><p>小蓝中转站 主要解决的是后两件事。<br> 工具本身仍然优先从各自官方入口下载；真正接模型时，再通过 小蓝中转站 把地址、Key、模型和账单统一起来。</p><h2 id="适合谁" tabindex="-1">适合谁 <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁&quot;">​</a></h2><ul><li>想用 Claude Code、Codex、Gemini CLI 的开发者</li><li>想用 Cherry Studio 管理多模型的用户</li><li>需要国内直连 AI 接口的团队</li><li>想把账单、Key、模型统一管理的人</li></ul><h2 id="你会在这里统一管理什么" tabindex="-1">你会在这里统一管理什么 <a class="header-anchor" href="#你会在这里统一管理什么" aria-label="Permalink to &quot;你会在这里统一管理什么&quot;">​</a></h2><p>大多数用户最终会把这几件事都集中到同一个控制台里处理：</p><ul><li>账号和余额</li><li>每个工具使用的 Key</li><li>当前可用模型和价格</li><li>请求日志和异常排查</li></ul><p>这也是 小蓝中转站 和“只提供一个 API 地址”的区别。它不仅是一个入口，还把后续最常用的管理动作一起收进了控制台。</p><p>真正用起来以后，最常见的日常动作通常就是这几类：</p><ul><li>新装一个工具后，回来创建一把专属 Key</li><li>想换模型时，回模型广场复制模型名</li><li>遇到报错时，回日志里按 Key 查请求</li><li>想控制预算时，回令牌管理里改额度或模型权限</li></ul><h2 id="常用入口" tabindex="-1">常用入口 <a class="header-anchor" href="#常用入口" aria-label="Permalink to &quot;常用入口&quot;">​</a></h2><ul><li>API Endpoint：<code>https://xiaolan1.cn/v1</code></li><li>注册与控制台：<a href="https://xiaolan1.cn" target="_blank" rel="noreferrer">https://xiaolan1.cn</a></li><li>模型价格：<a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">https://xiaolan1.cn/pricing</a></li><li>问题排查：<a href="/support/faq">常见问题</a></li><li>新手路线：<a href="/beginner/windows">Windows 快速接入</a> / <a href="/beginner/macos">macOS 快速接入</a></li></ul><p>如果你现在正卡在“某个工具到底该填根地址还是 <code>/v1</code>”，先不要只盯这一页。<br> 直接去看：</p><ul><li><a href="/intro/overview">为什么需要 小蓝中转站 网关？</a></li><li><a href="/support/troubleshooting">排障手册</a></li></ul>',21)])])}const b=l(t,[["render",n]]);export{c as __pageData,b as default};
